/**
 * Finds the largest index i such that nums[i] <= X. Returns -1 if no such element exists.
 * This is equivalent to finding the index before the first element strictly greater than X.
 */
function find_jX(nums, X) {
    let low = 0;
    let high = nums.length - 1;
    let result = -1;

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        if (nums[mid] <= X) {
            result = mid;
            low = mid + 1; // Try to find a larger index
        } else {
            high = mid - 1; // Too large
        }
    }
    return result;
}

function solve(nums, queries) {
    const N = nums.length;

    // Step 1: Precalculate prefix sums of even numbers
    // P[i] stores the count of even numbers in nums[0...i]
    const P = new Array(N).fill(0);
    for (let i = 0; i < N; i++) {
        P[i] = (i > 0 ? P[i - 1] : 0);
        if (nums[i] % 2 === 0) {
            P[i]++;
        }
    }

    const results = [];

    for (const query of queries) {
        const [l, r, k] = query;

        // Binary Search for the smallest even number X such that:
        // X/2 - C(X) >= k
        // where C(X) is the count of even numbers in nums[l..r] that are <= X.

        // Search range for X. Minimum possible answer is 2*k. Maximum is roughly 2*k + N.
        let L = 2;
        // A safe upper bound since k <= 10^9 and N <= 10^5. 4*10^9 is safe.
        let R = 4000000000; 
        let ansX = R + 2; 

        while (L <= R) {
            // Calculate midpoint, ensuring it's an even number for the search space.
            let X_mid = Math.floor((L + R) / 2);
            let X = X_mid % 2 === 0 ? X_mid : X_mid - 1;

            // If X falls below L, we might skip, but since L starts even (2) or we adjust L/R correctly, this shouldn't happen if L<=R.
            if (X < L) {
                if (X_mid % 2 !== 0) { // If X_mid was odd and thus X = X_mid - 1, and X < L, then L must be odd, but L starts even.
                    // If L is odd, we should start search from L+1. Adjusting L/R boundary logic handles this better.
                    break; 
                }
            }

            // 1. Find jX: largest index such that nums[jX] <= X
            const jX = find_jX(nums, X);

            let C_X = 0;
            if (jX >= l) {
                // 2. Effective right boundary r' = min(r, jX)
                const r_prime = Math.min(r, jX);

                // 3. Calculate C(X): count of evens in nums[l...r']
                let count_up_to_r_prime = P[r_prime];
                let count_before_l;
                if (l > 0) {
                    count_before_l = P[l - 1];
                } else {
                    count_before_l = 0;
                }
                C_X = count_up_to_r_prime - count_before_l;
            }

            // 4. Check condition: X/2 - C(X) >= k
            // Since X is even, X/2 is safe.
            const remaining_count = (X / 2) - C_X;

            if (remaining_count >= k) {
                // X is a possible answer. Try to find a smaller one.
                ansX = X;
                R = X - 2; // Search in even numbers below X
            } else {
                // X is too small, need a larger X.
                L = X + 2; // Search in even numbers above X
            }
        }
        results.push(ansX);
    }

    return results;
}

